final:
module RefModule(clk, rst, en, D, Q);
    input clk;
    input rst;
    input en;
    input [31:0] D;
    output reg [31:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            Q <= 32'b0;
        else if (en)
            Q <= D;
    end
endmodule
